+        let mut rows = Vec::with_capacity(1000);
+        for i in 0_i64..1000 {
+            rows.push(vec![
+                SqliteValue::Integer(i),
+                SqliteValue::Integer(i.wrapping_mul(31).wrapping_sub(7)),
