+        let rows = vec![vec![SqliteValue::Integer(7)]];
+        let row_refs: Vec<&[SqliteValue]> = rows.iter().map(Vec::as_slice).collect();
+        let mut out = Vec::with_capacity(4096);
+        let initial_cap = out.capacity();
+        let mut offsets = Vec::with_capacity(32);
